#include <OneWire.h>
#include <DallasTemperature.h>
#include <SD.h>
#define OW_PIN 2
#define SD_CS 10
#define TEG_V_PIN A0
#define LOG_INTERVAL 10000UL
OneWire ow(OW_PIN); DallasTemperature ds(&ow); File lg;
float cumEnergyMWh=0;
float mppt_tracker(float Voc){return Voc*0.50f;}
void initHardware(){
  ds.begin();SD.begin(SD_CS);
  lg=SD.open("teg.csv",FILE_WRITE);
  if(lg)lg.println("t_s,Th,Tc,dT,Voc,S_uVK,P_mW,E_mWh");
  Serial.begin(9600);
}
float readTemperatureSensor(int idx){ds.requestTemperatures();return ds.getTempCByIndex(idx);}
float readTEGVoltage(){return analogRead(TEG_V_PIN)*5.0f/1023.0f;}
void logSeebeckData(unsigned long t,float Th,float Tc,float Voc,float dt_s){
  float dT=Th-Tc;
  float S_uVK=(dT>0.5f)?Voc/dT*1e6f:0;
  float Vmpp=mppt_tracker(Voc);
  float R_int=1.5f;
  float P_mW=(Vmpp*Vmpp/R_int)*1000.0f;
  cumEnergyMWh+=P_mW*(dt_s/3600.0f);
  if(lg){lg.print(t);lg.print(',');lg.print(Th,2);lg.print(',');lg.print(Tc,2);lg.print(',');
  lg.print(dT,2);lg.print(',');lg.print(Voc,4);lg.print(',');lg.print(S_uVK,1);lg.print(',');
  lg.print(P_mW,3);lg.print(',');lg.println(cumEnergyMWh,4);lg.flush();}
  Serial.print("dT=");Serial.print(dT,1);Serial.print(" S=");Serial.print(S_uVK,1);Serial.print("uV/K P=");Serial.print(P_mW,2);Serial.println("mW");
}
void checkFaultSafety(float Th){
  if(Th>88.0f){Serial.println("FAULT:HOT_SIDE_OVERTEMP");lg.close();while(1);}
}
void setup(){initHardware();}
void loop(){
  static unsigned long prev=0;unsigned long now=millis();
  if(now-prev<LOG_INTERVAL)return;float dt=(now-prev)/1000.0f;prev=now;
  float Th=readTemperatureSensor(0);float Tc=readTemperatureSensor(1);
  checkFaultSafety(Th);
  float Voc=readTEGVoltage();
  logSeebeckData(now/1000,Th,Tc,Voc,dt);
}
